import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"附录B API 速查手册","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-b-api-reference.md","filePath":"chapters/appendix-b-api-reference.md"}'),c={name:"chapters/appendix-b-api-reference.md"};function a(s,t,i,h,n,l){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="附录b-api-速查手册" tabindex="-1">附录B API 速查手册 <a class="header-anchor" href="#附录b-api-速查手册" aria-label="Permalink to &quot;附录B API 速查手册&quot;">​</a></h1><p>本附录汇总 OpenSandbox 全部 HTTP API，按功能域分组，供开发过程中快速查阅。每个接口列出 HTTP 方法、路径、典型状态码及简要说明。详细的请求与响应 schema 请参考项目仓库中的 OpenAPI 定义文件。</p><h2 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h2><p>OpenSandbox 的不同组件使用独立的认证 Header：</p><table tabindex="0"><thead><tr><th>Header</th><th>适用组件</th><th>说明</th></tr></thead><tbody><tr><td><code>OPEN-SANDBOX-API-KEY</code></td><td>Server API</td><td>管理面 API 密钥，用于沙箱生命周期操作</td></tr><tr><td><code>X-EXECD-ACCESS-TOKEN</code></td><td>execd API</td><td>执行面访问令牌，随沙箱创建时生成</td></tr><tr><td><code>OPENSANDBOX-EGRESS-AUTH</code></td><td>Egress API</td><td>出站策略管理令牌</td></tr></tbody></table><h2 id="生命周期-api-server" tabindex="-1">生命周期 API（Server） <a class="header-anchor" href="#生命周期-api-server" aria-label="Permalink to &quot;生命周期 API（Server）&quot;">​</a></h2><p>Server 负责沙箱实例的创建、查询、销毁和状态管理。</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/sandboxes</code></td><td>202</td><td>创建沙箱实例。返回 202 表示异步创建已接受，沙箱将在后台完成初始化</td></tr><tr><td><code>GET</code></td><td><code>/sandboxes</code></td><td>200</td><td>列出所有沙箱实例，支持分页与状态过滤</td></tr><tr><td><code>GET</code></td><td><code>/sandboxes/{id}</code></td><td>200</td><td>查询指定沙箱的详细信息，包括状态、端点和元数据</td></tr><tr><td><code>DELETE</code></td><td><code>/sandboxes/{id}</code></td><td>204</td><td>销毁指定沙箱，释放所有关联资源。返回 204 表示删除成功无内容返回</td></tr><tr><td><code>POST</code></td><td><code>/sandboxes/{id}/pause</code></td><td>202</td><td>暂停沙箱，冻结容器进程但保留资源。适用于需要临时释放计算资源的场景</td></tr><tr><td><code>POST</code></td><td><code>/sandboxes/{id}/resume</code></td><td>202</td><td>恢复已暂停的沙箱，进程从冻结点继续执行</td></tr><tr><td><code>POST</code></td><td><code>/sandboxes/{id}/renew-expiration</code></td><td>200</td><td>续期沙箱的过期时间，防止自动回收</td></tr><tr><td><code>GET</code></td><td><code>/sandboxes/{id}/endpoints/{port}</code></td><td>200</td><td>获取沙箱指定端口的外部访问端点信息</td></tr><tr><td><code>*</code></td><td><code>/sandboxes/{id}/proxy/{port}/{path}</code></td><td>-</td><td>代理请求到沙箱内部服务。支持所有 HTTP 方法，路径和查询参数透传</td></tr></tbody></table><blockquote><p><strong>注意</strong>：<code>POST /sandboxes</code> 和暂停 / 恢复接口返回 202 而非 200，表明这些操作是异步执行的。客户端应通过轮询 <code>GET /sandboxes/{id}</code> 或监听事件来确认操作完成。</p></blockquote><h2 id="执行-api-execd" tabindex="-1">执行 API（execd） <a class="header-anchor" href="#执行-api-execd" aria-label="Permalink to &quot;执行 API（execd）&quot;">​</a></h2><p>execd 是运行在沙箱容器内部的守护进程，提供代码执行和命令运行能力。</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/code/context</code></td><td>200</td><td>设置代码执行上下文，包括环境变量、工作目录等预配置</td></tr><tr><td><code>POST</code></td><td><code>/code</code></td><td>200 (SSE)</td><td>提交代码执行请求，通过 SSE 流式返回执行输出。支持多语言，底层对接 Jupyter Kernel</td></tr><tr><td><code>DELETE</code></td><td><code>/code</code></td><td>200</td><td>中断当前正在执行的代码，强制终止 Kernel 中运行的任务</td></tr><tr><td><code>POST</code></td><td><code>/command</code></td><td>200</td><td>执行 Shell 命令，支持设置超时和工作目录</td></tr><tr><td><code>GET</code></td><td><code>/command/status/{id}</code></td><td>200</td><td>查询异步命令的执行状态，返回运行中、完成或失败</td></tr><tr><td><code>GET</code></td><td><code>/command/{id}/logs</code></td><td>200</td><td>获取指定命令的 stdout 和 stderr 输出日志</td></tr></tbody></table><blockquote><p><strong>SSE 说明</strong>：<code>POST /code</code> 接口使用 Server-Sent Events 协议推送执行结果。客户端需要以 SSE 模式读取响应体，事件类型包括 <code>stdout</code>、<code>stderr</code>、<code>result</code> 和 <code>error</code>。</p></blockquote><h2 id="文件-api-execd" tabindex="-1">文件 API（execd） <a class="header-anchor" href="#文件-api-execd" aria-label="Permalink to &quot;文件 API（execd）&quot;">​</a></h2><p>文件操作接口同样由 execd 提供，覆盖沙箱内文件系统的完整 CRUD 操作。</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/files/info</code></td><td>200</td><td>查询文件或目录的元信息，包括大小、权限、修改时间</td></tr><tr><td><code>DELETE</code></td><td><code>/files</code></td><td>200</td><td>删除指定文件</td></tr><tr><td><code>POST</code></td><td><code>/files/permissions</code></td><td>200</td><td>修改文件权限，等效于 chmod 操作</td></tr><tr><td><code>POST</code></td><td><code>/files/mv</code></td><td>200</td><td>移动或重命名文件</td></tr><tr><td><code>GET</code></td><td><code>/files/search</code></td><td>200</td><td>在指定目录下搜索文件，支持名称模式匹配</td></tr><tr><td><code>POST</code></td><td><code>/files/replace</code></td><td>200</td><td>搜索并替换文件内容，支持正则表达式</td></tr><tr><td><code>POST</code></td><td><code>/files/upload</code></td><td>200</td><td>上传文件到沙箱内指定路径</td></tr><tr><td><code>GET</code></td><td><code>/files/download</code></td><td>200</td><td>下载沙箱内的文件。支持 HTTP Range Header 实现断点续传和分片下载</td></tr><tr><td><code>POST</code></td><td><code>/directories</code></td><td>200</td><td>创建目录，支持递归创建（等效于 mkdir -p）</td></tr><tr><td><code>DELETE</code></td><td><code>/directories</code></td><td>200</td><td>删除目录及其内容</td></tr></tbody></table><h2 id="metrics-api-execd" tabindex="-1">Metrics API（execd） <a class="header-anchor" href="#metrics-api-execd" aria-label="Permalink to &quot;Metrics API（execd）&quot;">​</a></h2><p>用于监控沙箱内部的资源使用情况。</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/metrics</code></td><td>200</td><td>获取当前时刻的资源指标快照，包括 CPU、内存、磁盘使用率</td></tr><tr><td><code>GET</code></td><td><code>/metrics/watch</code></td><td>200 (SSE)</td><td>以 SSE 方式持续推送资源指标变化，适合实时监控面板</td></tr></tbody></table><h2 id="egress-api" tabindex="-1">Egress API <a class="header-anchor" href="#egress-api" aria-label="Permalink to &quot;Egress API&quot;">​</a></h2><p>管理沙箱的出站网络策略，控制沙箱内进程可以访问的外部地址。</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>状态码</th><th>说明</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/policy</code></td><td>200</td><td>获取当前沙箱的出站策略配置，包括允许和拒绝的 FQDN 列表</td></tr><tr><td><code>PATCH</code></td><td><code>/policy</code></td><td>200</td><td>增量更新出站策略，可添加或移除允许访问的域名</td></tr></tbody></table><h2 id="健康检查端点" tabindex="-1">健康检查端点 <a class="header-anchor" href="#健康检查端点" aria-label="Permalink to &quot;健康检查端点&quot;">​</a></h2><p>各组件均暴露健康检查端点，供 Kubernetes 探针和负载均衡器使用：</p><table tabindex="0"><thead><tr><th>路径</th><th>用途</th><th>说明</th></tr></thead><tbody><tr><td><code>/health</code></td><td>综合健康检查</td><td>返回组件的详细健康状态，包括依赖服务的连通性</td></tr><tr><td><code>/ping</code></td><td>存活探测</td><td>最轻量的存活检查，仅确认进程在运行</td></tr><tr><td><code>/status.ok</code></td><td>就绪探测</td><td>确认服务已完成初始化，可以接受流量</td></tr><tr><td><code>/healthz</code></td><td>Kubernetes 探针</td><td>兼容 Kubernetes 标准的健康检查路径</td></tr></tbody></table><h2 id="状态码约定" tabindex="-1">状态码约定 <a class="header-anchor" href="#状态码约定" aria-label="Permalink to &quot;状态码约定&quot;">​</a></h2><p>OpenSandbox API 遵循以下状态码约定：</p><ul><li><strong>200</strong>：请求成功，响应体包含结果数据</li><li><strong>202</strong>：异步操作已接受，操作将在后台完成</li><li><strong>204</strong>：操作成功，无响应体（常见于 DELETE）</li><li><strong>400</strong>：请求参数错误</li><li><strong>401</strong>：认证失败，缺少或无效的 API Key / Token</li><li><strong>404</strong>：目标资源不存在</li><li><strong>409</strong>：状态冲突，例如对已暂停的沙箱执行暂停操作</li><li><strong>429</strong>：请求频率超限</li><li><strong>500</strong>：服务端内部错误</li></ul>',28)])])}const P=d(c,[["render",a]]);export{p as __pageData,P as default};
